import requests, json
owner='stainlu'; repo='hermes-labyrinth'; num=7
base=f'https://api.github.com/repos/{owner}/{repo}'
pr=requests.get(f'{base}/pulls/{num}',headers={'Accept':'application/vnd.github+json'}).json()
reviews=requests.get(f'{base}/pulls/{num}/reviews',headers={'Accept':'application/vnd.github+json'}).json()
issue_comments=requests.get(f'{base}/issues/{num}/comments',headers={'Accept':'application/vnd.github+json'}).json()
review_comments=requests.get(f'{base}/pulls/{num}/comments',headers={'Accept':'application/vnd.github+json'}).json()
# check runs for head sha
sha=pr['head']['sha']
checks=requests.get(f'{base}/commits/{sha}/check-runs',headers={'Accept':'application/vnd.github+json'}).json()
statuses=requests.get(f'{base}/commits/{sha}/status',headers={'Accept':'application/vnd.github+json'}).json()
print(json.dumps({
 'pr': {
  'state': pr.get('state'), 'merged': pr.get('merged'), 'html_url': pr.get('html_url'),
  'head_sha': sha, 'updated_at': pr.get('updated_at'), 'merged_at': pr.get('merged_at'), 'closed_at': pr.get('closed_at')
 },
 'reviews': [
   {'id':r['id'],'user':r['user']['login'],'state':r['state'],'submitted_at':r['submitted_at'],'html_url':r['html_url']} for r in reviews
 ],
 'issue_comments': [
   {'id':c['id'],'user':c['user']['login'],'created_at':c['created_at'],'updated_at':c['updated_at'],'html_url':c['html_url']} for c in issue_comments
 ],
 'review_comments': [
   {'id':c['id'],'user':c['user']['login'],'path':c['path'],'created_at':c['created_at'],'html_url':c['html_url']} for c in review_comments
 ],
 'checks_summary': {
   'total_count': checks.get('total_count'),
   'conclusion_counts': {k: sum(1 for cr in checks.get('check_runs',[]) if cr.get('conclusion')==k) for k in sorted(set(cr.get('conclusion') for cr in checks.get('check_runs',[])))},
   'runs':[{'id':cr['id'],'name':cr['name'],'status':cr['status'],'conclusion':cr['conclusion'],'html_url':cr['html_url']} for cr in checks.get('check_runs',[])]
 },
 'combined_status': {'state':statuses.get('state'),'total_count':statuses.get('total_count')}
}, indent=2))
